<template>
    <div class="transition">
        <div class="nav">
            <van-icon name="arrow-left" @click="$router.back()" />
            <p>详情信息</p>
            <van-icon name="service-o" />
        </div>
<div class="navBg">
    <img src="../assets/trans.gif" alt="">
    <div class="right">
    <p>商家还没发货，请小主耐心等待哦~</p>
    <p>{{data._pay_time}}</p>
    </div>
</div>
<!-- 物流信息 -->
<van-steps :active="active" active-color="#FA877B">
  <van-step>待付款</van-step>
  <van-step>待发货</van-step>
  <van-step>待收货</van-step>
  <van-step>待评价</van-step>
</van-steps>
 <div class="address">
        <p class="big"><label>默认</label>{{data.real_name}}</p>
        <p>{{data.user_phone}}</p>
        <p>{{data.user_address}} </p>
          <img src="../assets/line.jpg" alt="">

      </div>

      <!-- 产品信息 -->
      <div class="product" v-for="(c,i) in product" :key="i">
           <img :src="c.productInfo.image" alt="">      
       <div class="msg">
           <div class="line1">
              {{c.productInfo.store_name}}
           </div>
           <div class="line2">
               <p> {{c.productInfo.attrInfo.suk}}</p>
              <span>x {{c.cart_num}}</span>
           </div>
           <div class="line3">￥{{c.productInfo.give_integral}}</div>
       </div>

      </div>
      <div class="confirm">
          <p>
              <span>订单编号</span>
              <span>{{data.order_id}}</span>
          </p>
           <p>
              <span>下单时间</span>
              <span>{{data._pay_time}}</span>
          </p>
           <p>
              <span>订单类型</span>
              <span>普通类型</span>
          </p>
           <p>
              <span>支付方式</span>
              <span>余额支付</span>
          </p>
           <p>
              <span>支付金额</span>
              <span>{{data.total_price}}</span>
          </p>
      </div>

    </div>
</template>
<script>
export default {
    props:['_num'],
    data(){
        return{
          data:'',
          active:1,
          product:[]
        }
    },
      created(){
    
        this.axios.get("/api/order/detail/"+this._num).then(d=>{
            this.data = d.data.data;
            this.product = d.data.data.cartInfo;
            console.log("订单支付成功=>",d.data.data);
        })
    }
}
</script>

<style lang="less" scoped>
.transition{
    font-size: 16px;
    height: 100vh;
     .nav{
        height: 50px;
        background-color: #fff;
        display: flex;
        justify-content: space-between;
        padding: 0 10px;
        align-items: center;
        p{
            height: 100%;
            margin: 0;
            line-height:50px;
        }
    }
    .navBg{
        width: 95%;
        margin: 10px auto;
        display: flex;
        justify-content: space-around;
        border-radius: 10px;
        border: 2px solid #FA877B;
        padding: 0 10px;
        box-sizing: border-box;
        height: 80px;
        margin-bottom: 20px;
        background-color: white;
        img{
            width: 60px;
            height: 80px;
        }
        .right{
            font-size: 16px;
            p{
                &:nth-child(1){
                    font-weight: bold;
                }
            }
        }
    }
     .address{
      height: 90px;
      background-color: #fff;
      margin: 10px auto;
      padding: 0 10px;
      font-size: 14px;
