      border-top: 10px solid rgb(245, 244, 244);
      p{
          line-height: .8;
          margin-left: 10px;
      }
      p.big{
          font-weight: bold;
      label{
          color: #fff;
          font-size: 12px;
          padding: 2px;
          border-radius: 3px;
          background-color: #FA877B;
          margin-right: 10px;
      }
      }
      img{
          width: 100%;
      }
  }
  .confirm{
      font-size: 14px;
      padding: 0 10px;
      border-bottom: 10px solid rgb(245, 244, 244);
      p{
          display: flex;
          justify-content: space-between;
          line-height: 26px;
      }
  }
   .product{
     display: flex;
     justify-content: space-around;
     background-color: #fff;
     padding: 5px;
     img{
         width: 25%;
         height: auto;
     }
     .msg{
         width: 70%;
         .line1{
             overflow: hidden;
             text-overflow:ellipsis ;
             white-space: nowrap;
         }
         .line2{
             display: flex;
             justify-content: space-between;
             align-items: center;
             color: #666;
             font-size: 14px;
         }
         .line3{
             color: #FA877B;
         }
     }
  }
}
</style>